# ==========================================================
# MARKET DATA FUNCTION
# ==========================================================

@st.cache_data(

    ttl=60

)

def load_market_data(

    symbol

):

    try:

        ticker = yf.Ticker(

            symbol

        )

        history = ticker.history(

            period="2d"

        )

        if history.empty:

            return None

        close = history["Close"]

        price = float(

            close.iloc[-1]

        )

        previous = float(

            close.iloc[-2]

        )

        change = (

            (price - previous)

            / previous

        ) * 100

        return {

            "price": price,

            "change": change

        }

    except Exception:

        return None

