@st.cache_data(

    ttl=300

)

def load_gold_news():

    url = (

        "https://feeds.finance.yahoo.com/rss/2.0/headline"

        "?s=GC=F"

        "&region=US"

        "&lang=en-US"

    )

    try:

        response = requests.get(

            url,

            timeout=REQUEST_TIMEOUT

        )

        soup = BeautifulSoup(

            response.content,

            "xml"

        )

        items = soup.find_all(

            "item"

        )

        news = []

        for item in items[:20]:

            news.append(

                {

                    "title": item.title.text,

                    "link": item.link.text,

                    "date": item.pubDate.text

                }

            )

        return news

    except Exception:

        return []

