# ==========================================================
# MARKET SENTIMENT
# ==========================================================

def calculate_market_sentiment():

    score = 0

    details = []

    if gold_data is not None:

        if gold_data["change"] > 0:

            score += 1

            details.append(

                "Gold tăng"

            )

        else:

            score -= 1

            details.append(

                "Gold giảm"

            )

    if dxy_data is not None:

        if dxy_data["change"] > 0:

            score -= 1

            details.append(

                "DXY tăng"

            )

        else:

            score += 1

            details.append(

                "DXY giảm"

            )

    if sp500_data is not None:

        if sp500_data["change"] > 0:

            score += 1

            details.append(

                "S&P500 tăng"

            )

        else:

            score -= 1

            details.append(

                "S&P500 giảm"

            )

    if score >= 2:

        sentiment = "Bullish"

    elif score <= -2:

        sentiment = "Bearish"

    else:

        sentiment = "Neutral"

    return sentiment, details

# ==========================================================
# DASHBOARD SENTIMENT
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "Market Sentiment"

    )

    sentiment, sentiment_detail = calculate_market_sentiment()

    st.metric(

        "Current Sentiment",

        sentiment

    )

    for item in sentiment_detail:

        st.write(

            "•",

            item

        )

