# ==========================================================

def calculate_fear_greed():

    score = 50

    if gold_data is not None:

        if gold_data["change"] > 1:

            score += 10

        elif gold_data["change"] < -1:

            score -= 10

    if dxy_data is not None:

        if dxy_data["change"] > 0.5:

            score -= 10

        elif dxy_data["change"] < -0.5:

            score += 10

    if sp500_data is not None:

        if sp500_data["change"] > 1:

            score += 15

        elif sp500_data["change"] < -1:

            score -= 15

    score = max(

        0,

        min(

            score,

            100

        )

    )

    return score

# ==========================================================
# DASHBOARD FEAR & GREED
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "Fear & Greed"

    )

    fg_score = calculate_fear_greed()

    st.progress(

        fg_score / 100

    )

    st.metric(

        "Index",

        fg_score

    )

    if fg_score >= 75:

        st.success(

            "Extreme Greed"

        )

    elif fg_score >= 55:

        st.info(

            "Greed"

        )

    elif fg_score >= 45:

        st.warning(

            "Neutral"

        )

    elif fg_score >= 25:

        st.warning(

            "Fear"

        )

    else:

        st.error(

            "Extreme Fear"

        )

