def generate_gold_signal():

    score = 0

    reasons = []

    if gold_data is not None:

        if gold_data["change"] > 0:

            score += 1

            reasons.append(

                "Gold đang tăng."

            )

        else:

            score -= 1

            reasons.append(

                "Gold đang giảm."

            )

    if dxy_data is not None:

        if dxy_data["change"] < 0:

            score += 1

            reasons.append(

                "DXY suy yếu."

            )

        else:

            score -= 1

            reasons.append(

                "DXY mạnh lên."

            )

    if sp500_data is not None:

        if sp500_data["change"] < 0:

            score += 1

            reasons.append(

                "Chứng khoán Mỹ suy yếu."

            )

        else:

            reasons.append(

                "Chứng khoán Mỹ tích cực."

            )

    if score >= 2:

        signal = "BUY"

    elif score <= -2:

        signal = "SELL"

    else:

        signal = "WAIT"

    return signal, reasons

# ==========================================================
# GOLD SIGNAL PAGE
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "Trading Signal"

    )

    signal, signal_reason = generate_gold_signal()

    if signal == "BUY":

        st.success(

            "BUY"

        )

    elif signal == "SELL":

        st.error(

            "SELL"

        )

    else:

        st.warning(

            "WAIT"

        )

    for reason in signal_reason:

        st.write(

            "•",

            reason

        )

