def analyze_gold_trend():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )

    if history.empty:

        return None

    history["MA20"] = history[

        "Close"

    ].rolling(

        20

    ).mean()

    history["MA50"] = history[

        "Close"

    ].rolling(

        50

    ).mean()

    latest_close = float(

        history["Close"].iloc[-1]

    )

    latest_ma20 = float(

        history["MA20"].iloc[-1]

    )

    latest_ma50 = float(

        history["MA50"].iloc[-1]

    )

    if latest_close > latest_ma20 > latest_ma50:

        trend = "Strong Uptrend"

    elif latest_close > latest_ma20:

        trend = "Uptrend"

    elif latest_close < latest_ma20 < latest_ma50:

        trend = "Strong Downtrend"

    elif latest_close < latest_ma20:

        trend = "Downtrend"

    else:

        trend = "Sideway"

    return {

        "trend": trend,

        "close": latest_close,

        "ma20": latest_ma20,

        "ma50": latest_ma50

    }

# ==========================================================
# GOLD TREND PAGE
# ==========================================================

