def calculate_volatility():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="1mo"

    )

    if history.empty:

        return None

    history["Range"] = (

        history["High"]

        - history["Low"]

    )

    average_range = float(

        history["Range"].mean()

    )

    max_range = float(

        history["Range"].max()

    )

    min_range = float(

        history["Range"].min()

    )

    latest_range = float(

        history["Range"].iloc[-1]

    )

    return {

        "average": average_range,

        "maximum": max_range,

        "minimum": min_range,

        "latest": latest_range

    }

