def analyze_volume():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )

    if history.empty:

        return None

    if "Volume" not in history.columns:

        return None

    average_volume = float(

        history["Volume"].mean()

    )

    latest_volume = float(

        history["Volume"].iloc[-1]

    )

    ratio = latest_volume / average_volume

    if ratio >= 1.5:

        status = "Very High"

    elif ratio >= 1.1:

        status = "High"

    elif ratio >= 0.8:

        status = "Normal"

    else:

        status = "Low"

    return {

        "latest": latest_volume,

        "average": average_volume,

        "ratio": ratio,

        "status": status

    }

