# ==========================================================
# RSI CALCULATOR
# ==========================================================

def calculate_rsi(

    period=14

):

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="6mo"

    )

    if history.empty:

        return None

    delta = history[

        "Close"

    ].diff()

    gain = delta.where(

        delta > 0,

        0

    )

    loss = -delta.where(

        delta < 0,

        0

    )

    average_gain = gain.rolling(

        period

    ).mean()

    average_loss = loss.rolling(

        period

    ).mean()

    rs = average_gain / average_loss

    rsi = 100 - (

        100 / (

            1 + rs

        )

    )

    latest = float(

        rsi.iloc[-1]

    )

    if latest >= 70:

        signal = "Overbought"

    elif latest <= 30:

        signal = "Oversold"

    else:

        signal = "Neutral"

    return {

        "rsi": latest,

        "signal": signal

    }

# ==========================================================
# GOLD RSI
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "RSI Indicator"

    )

    rsi_data = calculate_rsi()

    if rsi_data is None:

        st.warning(

            "Không thể tính RSI."

        )

    else:

        st.metric(

            "RSI (14)",

            round(

                rsi_data["rsi"],

                2

            )

        )

        st.write(

            "Signal:",

            rsi_data["signal"]

        )

