# ==========================================================

def calculate_macd():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="6mo"

    )

    if history.empty:

        return None

    close = history[

        "Close"

    ]

    ema12 = close.ewm(

        span=12,

        adjust=False

    ).mean()

    ema26 = close.ewm(

        span=26,

        adjust=False

    ).mean()

    macd = ema12 - ema26

    signal = macd.ewm(

        span=9,

        adjust=False

    ).mean()

    histogram = macd - signal

    return {

        "macd": float(

            macd.iloc[-1]

        ),

        "signal": float(

            signal.iloc[-1]

        ),

        "histogram": float(

            histogram.iloc[-1]

        )

    }

