# ==========================================================
# ATR CALCULATOR
# ==========================================================

def calculate_atr(

    period=14

):

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="6mo"

    )

    if history.empty:

        return None

    high = history[

        "High"

    ]

    low = history[

        "Low"

    ]

    close = history[

        "Close"

    ]

    previous_close = close.shift(

        1

    )

    tr = pd.concat(

        [

            high - low,

            (high - previous_close).abs(),

            (low - previous_close).abs()

        ],

        axis=1

    ).max(

        axis=1

    )

    atr = tr.rolling(

        period

    ).mean()

    latest = float(

        atr.iloc[-1]

    )

    return latest

