# TREND STRENGTH ANALYZER
# ==========================================================

def calculate_trend_strength():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="6mo"

    )

    if history.empty:

        return None

    close = history["Close"]

    change = (

        close.iloc[-1]

        -

        close.iloc[-20]

    )

    percentage = (

        change

        /

        close.iloc[-20]

    ) * 100

    if percentage >= 5:

        strength = "Very Strong Uptrend"

    elif percentage >= 2:

        strength = "Strong Uptrend"

    elif percentage > 0:

        strength = "Weak Uptrend"

    elif percentage <= -5:

        strength = "Very Strong Downtrend"

    elif percentage <= -2:

        strength = "Strong Downtrend"

    elif percentage < 0:

        strength = "Weak Downtrend"

    else:

        strength = "Sideway"

