# ==========================================================

def calculate_market_risk():

    risk_score = 50

    reasons = []

    if gold_data:

        if abs(gold_data["change"]) > 2:

            risk_score += 15

            reasons.append(

                "Gold biến động mạnh."

            )

        else:

            risk_score -= 5

            reasons.append(

                "Gold ổn định."

            )

    if dxy_data:

        if abs(dxy_data["change"]) > 1:

            risk_score += 15

            reasons.append(

                "USD biến động cao."

            )

        else:

            risk_score -= 5

            reasons.append(

                "USD ổn định."

            )

    if sp500_data:

        if sp500_data["change"] < -1:

            risk_score += 20

            reasons.append(

                "Chứng khoán giảm mạnh."

            )

        elif sp500_data["change"] > 1:

            risk_score -= 5

            reasons.append(

                "Thị trường tích cực."

            )

    risk_score = max(

        0,

        min(

            risk_score,

            100

        )

    )

    if risk_score >= 80:

        level = "High Risk"

    elif risk_score >= 60:

        level = "Medium Risk"

    else:

        level = "Low Risk"

    return {

        "score": risk_score,

        "level": level,

        "reasons": reasons

    }

# ==========================================================
# RISK PAGE
# ==========================================================

if st.session_state.page == "Macro":

    st.divider()

    st.subheader(

        "Market Risk"

    )

    risk = calculate_market_risk()

    st.progress(

        risk["score"] / 100

    )

    st.metric(

        "Risk Score",

        f'{risk["score"]}/100'

    )

    st.info(

        risk["level"]

    )

    for reason in risk["reasons"]:

        st.write(

            "•",

            reason

        )

