def market_session():

    hour = datetime.utcnow().hour

    if 0 <= hour < 7:

        return "Asia Session"

    elif 7 <= hour < 13:

        return "London Session"

    elif 13 <= hour < 21:

        return "New York Session"

    else:

        return "Market Transition"

