def analyze_trading_session():

    hour = datetime.utcnow().hour

    if 0 <= hour < 8:

        return {

            "session": "Asia",

            "volatility": "Medium"

        }

    elif 8 <= hour < 16:

        return {

            "session": "London",

            "volatility": "High"

        }

    elif 16 <= hour < 24:

        return {

            "session": "New York",

            "volatility": "Very High"

        }

    return {

        "session": "Unknown",

        "volatility": "Low"

    }

