def check_alerts():

    triggered = []

    market_data = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for alert in st.session_state.alerts:

        if not alert["active"]:

            continue

        data = market_data.get(

            alert["symbol"]

        )

        if data is None:

            continue

        price = data["price"]

        if alert["condition"] == "Above":

            if price >= alert["target"]:

                triggered.append(

                    alert

                )

        if alert["condition"] == "Below":

            if price <= alert["target"]:

                triggered.append(

                    alert

                )

    return triggered


