# ==========================================================

def calculate_portfolio():

    result = []

    market = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for item in st.session_state.portfolio:

        current = market.get(

            item["symbol"]

        )

        if current is None:

            continue

        pnl = (

            current["price"]

            -

            item["entry_price"]

        ) * item["amount"]

        result.append(

            {

                "Symbol": item["symbol"],

                "Amount": item["amount"],

                "Entry": item["entry_price"],

                "Current": current["price"],

                "PnL": round(

                    pnl,

                    2

                )

            }

        )

    return pd.DataFrame(

        result

    )


