def add_trade_record(

    symbol,

    direction,

    entry,

    exit_price,

    volume,

    note

):

    profit = (

        exit_price - entry

    ) * volume

    if direction == "SELL":

        profit = (

            entry - exit_price

        ) * volume

    trade = {

        "Time": current_time(),

        "Symbol": symbol,

        "Direction": direction,

        "Entry": entry,

        "Exit": exit_price,

        "Volume": volume,

        "Profit": round(

            profit,

            2

        ),

        "Note": note

    }

    st.session_state.journal.append(

        trade

    )

    log(

        "INFO",

        f"Trade saved {symbol}"

    )


