# ==========================================================

def analyze_trading_performance():

    if len(

        st.session_state.journal

    ) == 0:

        return {

            "total": 0,

            "wins": 0,

            "losses": 0,

            "winrate": 0,

            "profit": 0

        }

    total = len(

        st.session_state.journal

    )

    wins = 0

    losses = 0

    total_profit = 0

    for trade in st.session_state.journal:

        profit = trade["Profit"]

        total_profit += profit

        if profit > 0:

            wins += 1

        else:

            losses += 1

    winrate = (

        wins

        /

        total

    ) * 100

    return {

        "total": total,

        "wins": wins,

        "losses": losses,

        "winrate": winrate,

        "profit": total_profit

    }


