def ai_decision_engine():

    score = 50

    factors = []

    if gold_data:

        if gold_data["change"] > 0:

            score += 15

            factors.append(

                "Gold momentum positive"

            )

        else:

            score -= 15

            factors.append(

                "Gold momentum negative"

            )

    if dxy_data:

        if dxy_data["change"] < 0:

            score += 15

            factors.append(

                "USD weakness supports Gold"

            )

        else:

            score -= 15

            factors.append(

                "USD strength pressures Gold"

            )

    if sp500_data:

        if sp500_data["change"] > 0:

            score += 10

            factors.append(

                "Risk appetite positive"

            )

        else:

            score -= 10

            factors.append(

                "Risk sentiment weak"

            )

    score = max(

        0,

        min(

            score,

            100

        )

    )

    if score >= 75:

        decision = "BUY BIAS"

    elif score <= 25:

        decision = "SELL BIAS"

    else:

        decision = "WAIT"

    return {

        "score": score,

        "decision": decision,

        "factors": factors

    }


