def calculate_economic_impact():

    impact_score = 50

    factors = []

    if dxy_data:

        if dxy_data["change"] > 0:

            impact_score -= 10

            factors.append(

                "USD strength may pressure Gold"

            )

        else:

            impact_score += 10

            factors.append(

                "USD weakness supports Gold"

            )

    if gold_data:

        if gold_data["change"] > 0:

            impact_score += 10

            factors.append(

                "Gold momentum positive"

            )

        else:

            impact_score -= 10

            factors.append(

                "Gold momentum negative"

            )

    if sp500_data:

        if sp500_data["change"] < 0:

            impact_score += 5

            factors.append(

                "Risk aversion increases"

            )

        else:

            factors.append(

                "Risk appetite stable"

            )

    impact_score = max(

        0,

        min(

            impact_score,

            100

        )

    )

    if impact_score >= 70:

        status = "Positive For Gold"

    elif impact_score <= 30:

        status = "Negative For Gold"

    else:

        status = "Neutral"


    return {

        "score": impact_score,

        "status": status,

        "factors": factors

    }


