def market_scanner():

    results = []

    markets = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for name, data in markets.items():

        if data is None:

            continue

        change = data["change"]

        if change >= 1:

            signal = "Strong Buy"

        elif change > 0:

            signal = "Buy"

        elif change <= -1:

            signal = "Strong Sell"

        elif change < 0:

            signal = "Sell"

        else:

            signal = "Neutral"


        results.append(

            {

                "Market": name,

                "Price": round(

                    data["price"],

                    2

                ),

                "Change": round(

                    change,

                    2

                ),

                "Signal": signal

            }

        )

    return pd.DataFrame(

        results

    )


# ==========================================================
# SCANNER DISPLAY
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "🔎 Market Scanner"

    )

    scanner_df = market_scanner()

    st.dataframe(

        scanner_df,

        use_container_width=True,

        hide_index=True

    )


# ==========================================================
# TOP MOVERS
# ==========================================================

def find_top_movers():

    scanner = market_scanner()

    if scanner.empty:

        return None, None

    highest = scanner.sort_values(

        "Change",

        ascending=False

    ).iloc[0]

    lowest = scanner.sort_values(

        "Change",

        ascending=True

    ).iloc[0]

    return highest, lowest


# ==========================================================
# TOP MOVERS DISPLAY
# ==========================================================

if st.session_state.page == "Dashboard":

    top, bottom = find_top_movers()

    if top is not None:

        col1, col2 = st.columns(

            2

        )

        with col1:

            st.success(

                f"🚀 Strongest: {top['Market']} "

                f"{top['Change']}%"

            )

        with col2:

            st.error(

                f"📉 Weakest: {bottom['Market']} "

                f"{bottom['Change']}%"

            )


# ==========================================================
# MARKET RANKING
# ==========================================================

def market_ranking():

    scanner = market_scanner()

    if scanner.empty:

        return scanner

    ranking = scanner.sort_values(

        "Change",

        ascending=False

    )

    ranking.insert(

        0,

        "Rank",

        range(

            1,

            len(ranking)+1

        )

    )

    return ranking


