def market_strength_score():

    results = []

    markets = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for name, data in markets.items():

        if data is None:

            continue

        score = 50

        change = data["change"]

        score += change * 10

        score = max(

            0,

            min(

                score,

                100

            )

        )

        results.append(

            {

                "Market": name,

                "Strength": round(

                    score,

                    1

                )

            }

        )

    return pd.DataFrame(

        results

    )


