# ==========================================================
# POSITION SIZE CALCULATOR
# ==========================================================

def calculate_position_size(

    risk_money,

    stop_loss_distance

):

    if stop_loss_distance <= 0:

        return 0

    position = (

        risk_money

        /

        stop_loss_distance

    )

    return round(

        position,

        2

    )


# ==========================================================
# POSITION SIZE PANEL
