def calculate_trade_statistics():

    if len(

        st.session_state.journal

    ) == 0:

        return {

            "total": 0,

            "profit": 0,

            "average": 0,

            "best": 0,

            "worst": 0

        }

    profits = []

    for trade in st.session_state.journal:

        profits.append(

            trade["Profit"]

        )

    return {

        "total":

            len(profits),

        "profit":

            sum(profits),

        "average":

            sum(profits)

            /

            len(profits),

        "best":

            max(profits),

        "worst":

            min(profits)

    }


