# ==========================================================
# DRAWDOWN CALCULATOR
# ==========================================================

def calculate_drawdown():

    if len(

        st.session_state.equity_history

    ) == 0:

        return 0

    values = [

        item["Equity"]

        for item in st.session_state.equity_history

    ]

    peak = max(values)

    current = values[-1]

    if peak == 0:

        return 0

    drawdown = (

        peak - current

    ) / peak * 100

    return drawdown


# ==========================================================
# DRAWDOWN DISPLAY
# ==========================================================

if st.session_state.page == "Settings":

    st.metric(

        "Drawdown",

        f"{calculate_drawdown():.2f}%"

    )


