# ==========================================================

def calculate_performance_score():

    statistics = calculate_trade_statistics()

    score = 50

    if statistics["total"] > 0:

        if statistics["profit"] > 0:

            score += 25

        else:

            score -= 20

    drawdown = calculate_drawdown()

    if drawdown < 5:

        score += 10

    elif drawdown > 20:

        score -= 20

    return max(

        0,

        min(

            score,

            100

        )

    )


