def market_open_status():

    hour = datetime.utcnow().hour

    if 22 <= hour or hour < 0:

        return "Closed"

    elif 0 <= hour < 8:

        return "Asia"

    elif 8 <= hour < 16:

        return "London"

    else:

        return "New York"


