def market_watch():

    watch_data = []

    symbols = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data,

        "EURUSD": eurusd_data,

        "GBPUSD": gbpusd_data,

        "USDJPY": usdjpy_data

    }

    for name, data in symbols.items():

        if data is None:

            continue

        movement = data["change"]

        if movement > 1:

            state = "Strong Move"

        elif movement > 0:

            state = "Positive"

        elif movement < -1:

            state = "Strong Drop"

        elif movement < 0:

            state = "Negative"

        else:

            state = "Flat"


        watch_data.append(

            {

                "Asset": name,

                "Price": round(

                    data["price"],

                    4

                ),

                "Change": round(

                    movement,

                    2

                ),

                "State": state

            }

        )

    return pd.DataFrame(

        watch_data

    )


