def compare_markets():

    comparison = []

    markets = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for name, data in markets.items():

        if data is None:

            continue

        strength = 50

        if data["change"] > 0:

            strength += data["change"] * 8

        else:

            strength -= abs(

                data["change"]

            ) * 8


        strength = max(

            0,

            min(

                strength,

                100

            )

        )

        comparison.append(

            {

                "Market": name,

                "Price": round(

                    data["price"],

                    2

                ),

                "Strength": round(

                    strength,

                    1

                )

            }

        )

    return pd.DataFrame(

        comparison

    )


