# ==========================================================
# GOLD ENTRY ZONE ANALYZER
# ==========================================================

def calculate_entry_zone():

    sr = calculate_support_resistance()

    if sr is None:

        return None

    support = sr["support"]

    resistance = sr["resistance"]

    current = sr["price"]

    buy_zone = (

        support

        +

        (

            resistance

            -

            support

        )

        *

        0.35

    )

    sell_zone = (

        support

        +

        (

            resistance

            -

            support

        )

        *

        0.65

    )

    return {

        "Current":

            current,

        "Buy Zone":

            buy_zone,

        "Sell Zone":

            sell_zone

    }


