# ENTRY ZONE DISPLAY
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "🎯 Entry Zone"

    )

    entry_zone = calculate_entry_zone()

    if entry_zone:

        entry_df = pd.DataFrame(

            {

                "Zone":

                entry_zone.keys(),

                "Price":

                entry_zone.values()

            }

        )

        st.dataframe(

            entry_df,

            use_container_width=True,

            hide_index=True

        )


