# ==========================================================
# MARKET REGIME DETECTOR
# ==========================================================

def detect_market_regime():

    trend_score = 0

    volatility_score = 0

    if gold_data:

        if gold_data["change"] > 0:

            trend_score += 1

        else:

            trend_score -= 1

        if abs(

            gold_data["change"]

        ) > 1:

            volatility_score += 1


    if dxy_data:

        if dxy_data["change"] > 0:

            trend_score -= 1

        else:

            trend_score += 1


        if abs(

            dxy_data["change"]

        ) > 0.5:

            volatility_score += 1


    if volatility_score >= 2:

        volatility = "High"

    else:

        volatility = "Normal"


    if trend_score >= 2:

        regime = "Bull Market"

    elif trend_score <= -2:

        regime = "Bear Market"

    else:

        regime = "Sideway Market"


    return {

        "regime": regime,

        "volatility": volatility,

        "trend_score": trend_score

    }


# ==========================================================
# REGIME DISPLAY
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "🌐 Market Regime"

    )

    regime = detect_market_regime()

    col1, col2 = st.columns(

        2

    )

    with col1:

        st.metric(

            "Regime",

            regime["regime"]

        )

    with col2:

        st.metric(

            "Volatility",

            regime["volatility"]

        )


