    positive_words = [

        "rise",

        "gain",

        "growth",

        "bullish",

        "strong",

        "higher",

        "support"

    ]

    negative_words = [

        "fall",

        "drop",

        "weak",

        "bearish",

        "lower",

        "risk",

        "pressure"

    ]

    positive = 0

    negative = 0

    total = 0


    for article in st.session_state.news:

        text = str(

            article

        ).lower()

        total += 1

        for word in positive_words:

            if word in text:

                positive += 1

        for word in negative_words:

            if word in text:

                negative += 1


    if positive > negative:

        sentiment = "Positive"

    elif negative > positive:

        sentiment = "Negative"

    else:

        sentiment = "Neutral"


    return {

        "positive": positive,

        "negative": negative,

        "total": total,

        "sentiment": sentiment

    }


