def economic_rating():

    score = 50

    reasons = []


    if gold_data:

        if gold_data["change"] > 0:

            score += 10

            reasons.append(

                "Gold strength"

            )

        else:

            score -= 10

            reasons.append(

                "Gold weakness"

            )


    if dxy_data:

        if dxy_data["change"] < 0:

            score += 20

            reasons.append(

                "USD weakness"

            )

        else:

            score -= 20

            reasons.append(

                "USD strength"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return {

        "score": score,

        "reasons": reasons

    }


