# ==========================================================
# MARKET ALERT PRIORITY ENGINE
# ==========================================================

def calculate_alert_priority():

    priority = []

    markets = {

        "Gold": gold_data,

        "DXY": dxy_data,

        "S&P500": sp500_data,

        "NASDAQ": nasdaq_data

    }

    for name, data in markets.items():

        if data is None:

            continue

        change = abs(

            data["change"]

        )

        if change >= 3:

            level = "Critical"

        elif change >= 1.5:

            level = "High"

        elif change >= 0.5:

            level = "Medium"

        else:

            level = "Low"


        priority.append(

            {

                "Market": name,

                "Movement": round(

                    data["change"],

                    2

                ),

                "Priority": level

            }

        )


    return pd.DataFrame(

        priority

    )


