def calculate_entry_quality():

    score = 50

    reasons = []


    trend = analyze_gold_trend()

    rsi = calculate_rsi()

    macd = calculate_macd()


    if trend:

        if "Uptrend" in trend["trend"]:

            score += 15

            reasons.append(

                "Trend supports buyers"

            )

        elif "Downtrend" in trend["trend"]:

            score -= 15

            reasons.append(

                "Trend supports sellers"

            )


    if rsi:

        if rsi["signal"] == "Oversold":

            score += 10

            reasons.append(

                "RSI oversold"

            )

        elif rsi["signal"] == "Overbought":

            score -= 10

            reasons.append(

                "RSI overbought"

            )


    if macd:

        if macd["histogram"] > 0:

            score += 10

            reasons.append(

                "MACD positive"

            )

        else:

            score -= 10

            reasons.append(

                "MACD negative"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return {

        "score": score,

        "reasons": reasons

    }


