# ==========================================================
# GOLD MARKET STRUCTURE ANALYZER
# ==========================================================

def analyze_market_structure():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )

    if history.empty:

        return None


    recent_high = float(

        history["High"].tail(

            20

        ).max()

    )


    recent_low = float(

        history["Low"].tail(

            20

        ).min()

    )


    current_price = float(

        history["Close"].iloc[-1]

    )


    if current_price > recent_high * 0.98:

        structure = "Near Resistance"

    elif current_price < recent_low * 1.02:

        structure = "Near Support"

    else:

        structure = "Middle Range"


    return {

        "high": recent_high,

        "low": recent_low,

        "price": current_price,

        "structure": structure

    }


# ==========================================================
# STRUCTURE DISPLAY
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "🏗 Market Structure"

    )


    structure = analyze_market_structure()


    if structure:

        structure_df = pd.DataFrame(

            {

                "Level":

                [

                    "Resistance",

                    "Current",

                    "Support"

                ],

                "Price":

                [

                    structure["high"],

                    structure["price"],

                    structure["low"]

                ]

            }

        )


        st.dataframe(

            structure_df,

            use_container_width=True,

            hide_index=True

        )


        st.info(

            structure["structure"]

        )


