# ==========================================================
# MARKET PHASE DETECTOR
# ==========================================================

def detect_market_phase():

    phase_score = 0

    factors = []


    trend = analyze_gold_trend()

    volatility = calculate_volatility()

    momentum = calculate_market_momentum()


    if trend:

        if "Uptrend" in trend["trend"]:

            phase_score += 1

            factors.append(

                "Price trend is positive"

            )

        elif "Downtrend" in trend["trend"]:

            phase_score -= 1

            factors.append(

                "Price trend is negative"

            )


    if volatility:

        if volatility["latest"] > volatility["average"]:

            factors.append(

                "High volatility environment"

            )

        else:

            factors.append(

                "Normal volatility environment"

            )


    if momentum is not None:

        if not momentum.empty:

            gold_row = momentum[

                momentum["Market"]

                ==

                "Gold"

            ]

            if not gold_row.empty:

                value = float(

                    gold_row["Value"].iloc[0]

                )

                if value > 1:

                    phase_score += 1

                    factors.append(

                        "Strong momentum"

                    )


    if phase_score >= 2:

        phase = "Expansion"

    elif phase_score <= -1:

        phase = "Contraction"

    else:

        phase = "Accumulation"


    return {

        "phase": phase,

        "score": phase_score,

        "factors": factors

    }


