def analyze_market_opening():

    utc_hour = datetime.utcnow().hour

    if 0 <= utc_hour < 8:

        session = "Asian Session"

        liquidity = "Medium"

    elif 8 <= utc_hour < 16:

        session = "London Session"

        liquidity = "High"

    elif 16 <= utc_hour < 22:

        session = "New York Session"

        liquidity = "Very High"

    else:

        session = "Market Transition"

        liquidity = "Low"


    return {

        "session": session,

        "liquidity": liquidity

    }


