# ==========================================================
# GOLD MOMENTUM SCORE
# ==========================================================

def calculate_gold_momentum_score():

    score = 50

    factors = []


    if gold_data:

        change = gold_data["change"]

        if change > 0:

            score += 15

            factors.append(

                "Price momentum positive"

            )

        else:

            score -= 15

            factors.append(

                "Price momentum negative"

            )


    rsi = calculate_rsi()


    if rsi:

        if rsi["rsi"] < 30:

            score += 10

            factors.append(

                "RSI oversold"

            )

        elif rsi["rsi"] > 70:

            score -= 10

            factors.append(

                "RSI overbought"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return {

        "score": score,

        "factors": factors

    }


