def market_direction():

    score = 0


    if gold_data:

        score += 1 if gold_data["change"] > 0 else -1


    if dxy_data:

        score += 1 if dxy_data["change"] < 0 else -1


    if sp500_data:

        score += 1 if sp500_data["change"] > 0 else -1


    if score >= 2:

        return "UP"

    elif score <= -2:

        return "DOWN"

    else:

        return "SIDEWAY"


