# ==========================================================
# CANDLE PATTERN DETECTOR
# ==========================================================

def detect_candle_pattern():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )


    if history.empty:

        return None


    last = history.iloc[-1]

    previous = history.iloc[-2]


    current_body = abs(

        last["Close"]

        -

        last["Open"]

    )


    previous_body = abs(

        previous["Close"]

        -

        previous["Open"]

    )


    if (

        last["Close"] > last["Open"]

        and

        previous["Close"] < previous["Open"]

        and

        current_body > previous_body

    ):

        pattern = "Bullish Engulfing"


    elif (

        last["Close"] < last["Open"]

        and

        previous["Close"] > previous["Open"]

        and

        current_body > previous_body

    ):

        pattern = "Bearish Engulfing"


    elif current_body < (

        last["High"]

        -

        last["Low"]

    ) * 0.2:

        pattern = "Doji"


    else:

        pattern = "Normal"


    return pattern


# ==========================================================
# CANDLE PATTERN DISPLAY
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "🕯 Candle Pattern"

    )


    candle_pattern = detect_candle_pattern()


    if candle_pattern:

        st.metric(

            "Pattern",

            candle_pattern

        )


# ==========================================================
# GOLD BUY SELL PRESSURE
# ==========================================================

def calculate_buy_sell_pressure():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="1mo"

    )


    if history.empty:

        return None


    buyers = 0

    sellers = 0


    for _, candle in history.iterrows():

        if candle["Close"] > candle["Open"]:

            buyers += 1

        elif candle["Close"] < candle["Open"]:

            sellers += 1


    total = buyers + sellers


    if total == 0:

        return None


    buy_percent = (

        buyers

        /

        total

    ) * 100


    sell_percent = (

        sellers

        /

        total

    ) * 100


    return {

        "buy":

        buy_percent,

        "sell":

        sell_percent

    }


# ==========================================================
# PRESSURE DISPLAY
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "⚔ Buy / Sell Pressure"

    )


    pressure = calculate_buy_sell_pressure()


    if pressure:

        col1, col2 = st.columns(

            2

        )


        with col1:

            st.metric(

                "Buy Pressure",

                f'{pressure["buy"]:.2f}%'

            )


        with col2:

            st.metric(

                "Sell Pressure",

                f'{pressure["sell"]:.2f}%'

            )


# ==========================================================
# LIQUIDITY ANALYZER
# ==========================================================

def analyze_liquidity():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )


    if history.empty:

        return None


    volume = history["Volume"]


    average = float(

        volume.mean()

    )


    latest = float(

        volume.iloc[-1]

    )


    ratio = latest / average


    if ratio >= 1.5:

        status = "High Liquidity"

    elif ratio >= 1:

        status = "Normal Liquidity"

    else:

        status = "Low Liquidity"


    return {

        "ratio":

        ratio,

        "status":

        status

    }


