def calculate_trend_alignment():

    alignment = 0

    details = []


    ema = calculate_ema_signal()


    macd = calculate_macd()


    rsi = calculate_rsi()


    if ema:

        if "Bullish" in ema["signal"]:

            alignment += 1

            details.append(

                "EMA bullish alignment"

            )

        elif "Bearish" in ema["signal"]:

            alignment -= 1

            details.append(

                "EMA bearish alignment"

            )


    if macd:

        if macd["histogram"] > 0:

            alignment += 1

            details.append(

                "MACD positive"

            )

        else:

            alignment -= 1

            details.append(

                "MACD negative"

            )


    if rsi:

        if 40 < rsi["rsi"] < 70:

            alignment += 1

            details.append(

                "RSI healthy zone"

            )


    if alignment >= 2:

        result = "Aligned Bullish"

    elif alignment <= -2:

        result = "Aligned Bearish"

    else:

        result = "Mixed"


    return {

        "result":

        result,

        "score":

        alignment,

        "details":

        details

    }


