def create_gold_scorecard():

    score = 0

    maximum = 10

    items = []


    trend = analyze_gold_trend()

    if trend:

        if "Uptrend" in trend["trend"]:

            score += 1

            items.append(

                {

                    "Factor":

                    "Trend",

                    "Status":

                    "Bullish"

                }

            )

        elif "Downtrend" in trend["trend"]:

            score -= 1

            items.append(

                {

                    "Factor":

                    "Trend",

                    "Status":

                    "Bearish"

                }

            )


    momentum = calculate_gold_momentum_score()


    if momentum:

        if momentum["score"] >= 60:

            score += 1

            items.append(

                {

                    "Factor":

                    "Momentum",

                    "Status":

                    "Positive"

                }

            )

        else:

            score -= 1

            items.append(

                {

                    "Factor":

                    "Momentum",

                    "Status":

                    "Weak"

                }

            )


    pressure = calculate_market_pressure_index()


    if pressure:

        if pressure["score"] >= 60:

            score += 1

            items.append(

                {

                    "Factor":

                    "Pressure",

                    "Status":

                    "Buying"

                }

            )

        else:

            score -= 1

            items.append(

                {

                    "Factor":

                    "Pressure",

                    "Status":

                    "Selling"

                }

            )


    confidence = gold_trade_confidence()


    if confidence["confidence"] >= 70:

        score += 1

        items.append(

            {

                "Factor":

                "Confidence",

                "Status":

                "High"

            }

        )


    final_score = int(

        (

            (

                score + maximum

            )

            /

            (

                maximum * 2

            )

        )

        *

        100

    )


    return {

        "score":

        final_score,

        "items":

        items

    }


