    if risk["level"] == "DANGER":

        return (

            "High risk market condition. "

            "Avoid aggressive positions."

        )


    if direction == "UP":

        return (

            "Market momentum favors buyers."

        )


    if direction == "DOWN":

        return (

            "Market momentum favors sellers."

        )


    return (

        "Market is waiting for confirmation."

    )


