# ==========================================================
# GOLD ENTRY CONFIRMATION SCORE
# ==========================================================

def calculate_confirmation_score():

    score = 0

    maximum = 5

    confirmations = []


    trend = analyze_gold_trend()

    if trend:

        if (

            "Uptrend"

            in

            trend["trend"]

        ):

            score += 1

            confirmations.append(

                "Trend bullish"

            )


    macd = calculate_macd()

    if macd:

        if macd["histogram"] > 0:

            score += 1

            confirmations.append(

                "MACD positive"

            )


    rsi = calculate_rsi()

    if rsi:

        if 30 < rsi["rsi"] < 70:

            score += 1

            confirmations.append(

                "RSI normal zone"

            )


    pressure = calculate_market_pressure_index()

    if pressure:

        if pressure["score"] > 50:

            score += 1

            confirmations.append(

                "Buying pressure"

            )


    volatility = calculate_volatility()

    if volatility:

        if volatility["latest"] <= volatility["average"]:

            score += 1

            confirmations.append(

                "Stable volatility"

            )


    percentage = int(

        (

            score

            /

            maximum

        )

        *

        100

    )


    return {

        "score":

        percentage,

        "confirmations":

        confirmations

    }


# ==========================================================
# CONFIRMATION SCORE DISPLAY
# ==========================================================

