# MARKET RISK REWARD MODEL
# ==========================================================

def calculate_dynamic_risk_reward():

    setup = generate_gold_setup()


    if (

        setup["Entry"] is None

        or

        setup["Stop Loss"] is None

        or

        setup["Take Profit"] is None

    ):

        return None


    risk = abs(

        setup["Entry"]

        -

        setup["Stop Loss"]

    )


    reward = abs(

        setup["Take Profit"]

        -

        setup["Entry"]

    )


    if risk == 0:

        ratio = 0

    else:

        ratio = reward / risk


    return {

        "risk":

        risk,

        "reward":

        reward,

        "ratio":

        ratio

    }


