def calculate_market_stability():

    stability = 100


    volatility = calculate_volatility()


    if volatility:

        if volatility["latest"] > volatility["average"]:

            stability -= 25


    risk = calculate_market_risk()


    stability -= risk["score"] * 0.3


    stability = max(

        0,

        min(

            stability,

            100

        )

    )


    return round(

        stability,

        1

    )


