def calculate_reversal_risk():

    risk = 0

    reasons = []


    reversal = detect_trend_reversal()


    if reversal:

        if reversal["signal"] != "No Reversal":

            risk += 40

            reasons.append(

                reversal["signal"]

            )


    candle = detect_candle_pattern()


    if candle:

        if candle in [

            "Bearish Engulfing",

            "Doji"

        ]:

            risk += 20

            reasons.append(

                "Warning candle pattern"

            )


    rsi = calculate_rsi()


    if rsi:

        if rsi["rsi"] > 70:

            risk += 20

            reasons.append(

                "RSI overbought"

            )


        elif rsi["rsi"] < 30:

            risk += 20

            reasons.append(

                "RSI oversold"

            )


    risk = max(

        0,

        min(

            risk,

            100

        )

    )


    if risk >= 70:

        level = "High"

    elif risk >= 40:

        level = "Medium"

    else:

        level = "Low"


    return {

        "risk":

        risk,

        "level":

        level,

        "reasons":

        reasons

    }


