# ==========================================================
# GOLD LIQUIDITY ZONE DETECTOR
# ==========================================================

def detect_liquidity_zone():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="3mo"

    )


    if history.empty:

        return None


    high_volume = history[

        history["Volume"]

        >

        history["Volume"].mean()

    ]


    if high_volume.empty:

        return None


    high_zone = high_volume["High"].max()

