# ==========================================================
# MARKET IMBALANCE DETECTOR
# ==========================================================

def detect_market_imbalance():

    pressure = calculate_buy_sell_pressure()


    if pressure is None:

        return "Unknown"


    difference = (

        pressure["buy"]

        -

        pressure["sell"]

    )


    if difference > 20:

        return "Buyer Imbalance"


    elif difference < -20:

        return "Seller Imbalance"


    return "Balanced"


