# ==========================================================
# GOLD PRICE RANGE ANALYZER
# ==========================================================

def calculate_price_range():

    history = load_price_history(

        MARKET_SYMBOLS["Gold"],

        period="1mo"

    )


    if history.empty:

        return None


    highest = float(

        history["High"].max()

    )


    lowest = float(

        history["Low"].min()

    )


    current = float(

        history["Close"].iloc[-1]

    )


    range_size = (

        highest

        -

        lowest

    )


    position = (

        (

            current

            -

            lowest

        )

        /

        range_size

        *

        100

    ) if range_size else 0


    return {

        "high":

        highest,

        "low":

        lowest,

        "current":

        current,

        "position":

        position

    }


