def calculate_market_efficiency():

    score = 50


    volatility = calculate_volatility()


    if volatility:

        if volatility["latest"] < volatility["average"]:

            score += 15

        else:

            score -= 15


    liquidity = analyze_liquidity()


    if liquidity:

        if liquidity["ratio"] > 1:

            score += 10


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return score


