def calculate_gold_condition_score():

    score = 50

    factors = []


    trend = analyze_gold_trend()


    if trend:

        if "Uptrend" in trend["trend"]:

            score += 15

            factors.append(

                "Bullish trend"

            )


        elif "Downtrend" in trend["trend"]:

            score -= 15

            factors.append(

                "Bearish trend"

            )


    momentum = calculate_gold_momentum_score()


    if momentum:

        if momentum["score"] >= 60:

            score += 15

            factors.append(

                "Strong momentum"

            )

        else:

            score -= 10

            factors.append(

                "Weak momentum"

            )


    smart_money = analyze_smart_money_flow()


    if smart_money:

        if smart_money["score"] >= 60:

            score += 10

            factors.append(

                "Positive money flow"

            )

        else:

            score -= 10

            factors.append(

                "Negative money flow"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    if score >= 75:

        condition = "Strong Bullish"

    elif score >= 60:

        condition = "Bullish"

    elif score <= 25:

        condition = "Strong Bearish"

    elif score <= 40:

        condition = "Bearish"

    else:

        condition = "Neutral"


    return {

        "score":

        score,

        "condition":

        condition,

        "factors":

        factors

    }


