# ==========================================================
# MARKET NOISE FILTER
# ==========================================================

def market_noise_filter():

    noise = 0

    reasons = []


    volatility = calculate_volatility()


    if volatility:

        if volatility["latest"] > (

            volatility["average"]

            *

            2

        ):

            noise += 40

            reasons.append(

                "Extreme volatility"

            )


    liquidity = analyze_liquidity()


    if liquidity:

        if liquidity["ratio"] < 0.7:

            noise += 30

            reasons.append(

                "Low liquidity"

            )


    candle = detect_candle_pattern()


    if candle == "Doji":

        noise += 20

        reasons.append(

            "Indecision candle"

        )


    noise = max(

        0,

        min(

            noise,

            100

        )

    )


    if noise >= 70:

        status = "High Noise"

    elif noise >= 40:

        status = "Medium Noise"

    else:

        status = "Clean Market"


    return {

        "noise":

        noise,

        "status":

        status,

        "reasons":

        reasons

    }


