# ==========================================================
# MARKET TREND CONSISTENCY ENGINE
# ==========================================================

def calculate_trend_consistency():

    consistency = 0

    details = []


    multi_tf = analyze_multi_timeframe()


    if not multi_tf.empty:

        bullish = len(

            multi_tf[

                multi_tf["Trend"]

                ==

                "Bullish"

            ]

        )


        bearish = len(

            multi_tf[

                multi_tf["Trend"]

                ==

                "Bearish"

            ]

        )


        if bullish > bearish:

            consistency = (

                bullish

                /

                len(multi_tf)

            ) * 100


            details.append(

                "Multiple timeframes bullish"

            )


        elif bearish > bullish:

            consistency = (

                bearish

                /

                len(multi_tf)

            ) * 100


            details.append(

                "Multiple timeframes bearish"

            )


        else:

            details.append(

                "Timeframes disagree"

            )


    return {

        "score":

        round(

            consistency,

            1

        ),

        "details":

        details

    }


