# ==========================================================
# SMART RISK CONTROLLER
# ==========================================================

def smart_risk_controller():

    risk_score = 100

    warnings = []


    drawdown = calculate_drawdown()


    if drawdown > 10:

        risk_score -= 30

        warnings.append(

            "Account drawdown high"

        )


    daily_status = check_daily_loss()


    if not daily_status:

        risk_score -= 40

        warnings.append(

            "Daily loss limit reached"

        )


    psychology = trade_warning()


    if len(psychology) > 0:

        risk_score -= 20

        warnings.append(

            "Trading psychology warning"

        )


    risk_score = max(

        0,

        risk_score

    )


    if risk_score >= 70:

        status = "Safe Trading"

    elif risk_score >= 40:

        status = "Caution"

    else:

        status = "Stop Trading"


    return {

        "score":

        risk_score,

        "status":

        status,

        "warnings":

        warnings

    }


