def market_decision_engine_v2():

    score = 0

    reasons = []


    final = calculate_final_gold_score()


    if final["score"] >= 70:

        score += 2

        reasons.append(

            "High quality market"

        )


    elif final["score"] < 40:

        score -= 2

        reasons.append(

            "Poor market quality"

        )


    operation = determine_operation_mode()


    if operation == "OPPORTUNITY MODE":

        score += 2

        reasons.append(

            "Opportunity mode active"

        )


    elif operation == "DEFENSIVE MODE":

        score -= 2

        reasons.append(

            "Defensive mode active"

        )


    if score >= 3:

        decision = "TRADE"

    elif score <= -2:

        decision = "AVOID"

    else:

        decision = "WAIT"


    return {

        "decision":

        decision,

        "score":

        score,

        "reasons":

        reasons

    }


