# ==========================================================
# MARKET PRESSURE BALANCE
# ==========================================================

def calculate_pressure_balance():

    pressure = calculate_buy_sell_pressure()


    if pressure is None:

        return None


    balance = (

        pressure["buy"]

        -

        pressure["sell"]

    )


    if balance > 25:

        status = "Buyer Control"

    elif balance < -25:

        status = "Seller Control"

    else:

        status = "Balanced"


    return {

        "balance":

        round(

            balance,

            2

        ),

        "status":

        status

    }


