def calculate_confidence_v2():

    score = 0

    reasons = []


    final_score = calculate_final_gold_score()

    consistency = calculate_trend_consistency()

    entry = market_entry_filter()


    if final_score["score"] >= 70:

        score += 40

        reasons.append(

            "High market score"

        )


    if consistency["score"] >= 70:

        score += 30

        reasons.append(

            "Trend agreement"

        )


    passed = sum(

        entry.values()

    )


    if passed >= 3:

        score += 30

        reasons.append(

            "Entry filters passed"

        )


    return {

        "score":

        min(

            score,

            100

        ),

        "reasons":

        reasons

    }


