def calculate_execution_readiness():

    score = 0

    reasons = []


    confidence = calculate_confidence_v2()

    risk = smart_risk_controller()

    noise = market_noise_filter()

    entry = market_entry_filter()


    if confidence["score"] >= 70:

        score += 30

        reasons.append(

            "Confidence level acceptable"

        )


    if risk["score"] >= 70:

        score += 25

        reasons.append(

            "Risk condition healthy"

        )


    if noise["noise"] < 40:

        score += 20

        reasons.append(

            "Market noise low"

        )


    passed = sum(

        entry.values()

    )


    if passed >= 3:

        score += 25

        reasons.append(

            "Entry conditions satisfied"

        )


    score = min(

        score,

        100

    )


    if score >= 80:

        status = "READY"

    elif score >= 50:

        status = "PREPARE"

    else:

        status = "NOT READY"


    return {

        "score":

        score,

        "status":

        status,

        "reasons":

        reasons

    }


