# ==========================================================
# MARKET OPPORTUNITY RADAR
# ==========================================================

def opportunity_radar():

    radar = {

        "Signal":

        "NONE",

        "Strength":

        0,

        "Reason":

        []

    }


    opportunity = calculate_opportunity_score_v2()

    confidence = calculate_confidence_v2()

    readiness = calculate_execution_readiness()


    strength = (

        opportunity["score"]

        +

        confidence["score"]

        +

        readiness["score"]

    ) / 3


    radar["Strength"] = round(

        strength,

        1

    )


    if strength >= 80:

        radar["Signal"] = "HIGH QUALITY"

    elif strength >= 60:

        radar["Signal"] = "POSSIBLE"

    else:

        radar["Signal"] = "WAIT"


    radar["Reason"] = (

        opportunity["factors"]

        +

        confidence["reasons"]

        +

        readiness["reasons"]

    )


    return radar


# ==========================================================
# RADAR DISPLAY
# ==========================================================

