def analyze_trading_session():

    hour = datetime.utcnow().hour


    if 0 <= hour < 8:

        session = "Asian"

    elif 8 <= hour < 16:

        session = "London"

    elif 16 <= hour < 22:

        session = "New York"

    else:

        session = "Transition"


    volatility = calculate_volatility()


    if volatility:

        if volatility["latest"] > volatility["average"]:

            activity = "High"

        else:

            activity = "Normal"

    else:

        activity = "Unknown"


    return {

        "session":

        session,

        "activity":

        activity

    }


