def momentum_direction_engine():

    bullish = 0

    bearish = 0

    reasons = []


    momentum = calculate_gold_momentum_score()


    if momentum["score"] >= 60:

        bullish += 1

        reasons.append(

            "Momentum supports buyers"

        )

    else:

        bearish += 1

        reasons.append(

            "Momentum weak"

        )


    pressure = calculate_market_pressure_index()


    if pressure["score"] >= 60:

        bullish += 1

        reasons.append(

            "Buying pressure"

        )

    else:

        bearish += 1

        reasons.append(

            "Selling pressure"

        )


    if bullish > bearish:

        direction = "UP"

    elif bearish > bullish:

        direction = "DOWN"

    else:

        direction = "SIDEWAY"


    return {

        "direction":

        direction,

        "bullish":

        bullish,

        "bearish":

        bearish,

        "reasons":

        reasons

    }


