# MARKET ENTRY ZONE QUALITY
# ==========================================================

def entry_zone_quality():

    score = 50

    reasons = []


    zone = calculate_entry_zone()


    if zone:

        current = zone["Current"]

        buy_zone = zone["Buy Zone"]

        sell_zone = zone["Sell Zone"]


        if current <= buy_zone:

            score += 20

            reasons.append(

                "Near buy zone"

            )


        elif current >= sell_zone:

            score += 20

            reasons.append(

                "Near sell zone"

            )


        else:

            reasons.append(

                "Middle zone"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return {

        "score":

        score,

        "reasons":

        reasons

    }


