# ==========================================================

def calculate_market_health():

    health = 100

    warnings = []


    volatility = calculate_volatility()

    if volatility:

        if volatility["latest"] > (

            volatility["average"]

            *

            2

        ):

            health -= 25

            warnings.append(

                "Extreme volatility"

            )


    liquidity = analyze_liquidity()


    if liquidity:

        if liquidity["ratio"] < 0.7:

            health -= 20

            warnings.append(

                "Low liquidity"

            )


    noise = market_noise_filter()


    if noise["noise"] > 60:

        health -= 20

        warnings.append(

            "High market noise"

        )


    health = max(

        0,

        health

    )


    if health >= 80:

        status = "Healthy Market"

    elif health >= 50:

        status = "Caution Market"

    else:

        status = "Unstable Market"


    return {

        "health":

        health,

        "status":

        status,

        "warnings":

        warnings

    }


# ==========================================================
# MARKET HEALTH DISPLAY
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "❤️ Market Health"

    )


    health = calculate_market_health()


    st.progress(

        health["health"]

        /

        100

    )


    st.metric(

        "Health",

        f'{health["health"]}/100'

    )


    st.info(

        health["status"]

    )


    for warning in health["warnings"]:

        st.warning(

            warning

        )


