# GOLD MARKET DOMINANCE INDEX
# ==========================================================

def calculate_gold_dominance():

    score = 50

    reasons = []


    gold = gold_data

    dxy = dxy_data


    if gold:

        if gold["change"] > 0:

            score += 20

            reasons.append(

                "Gold strength"

            )

        else:

            score -= 20

            reasons.append(

                "Gold weakness"

            )


    if dxy:

        if dxy["change"] < 0:

            score += 20

            reasons.append(

                "USD weakness supports gold"

            )

        else:

            score -= 20

            reasons.append(

                "USD strength pressures gold"

            )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    if score >= 70:

        status = "Gold Dominant"

    elif score <= 30:

        status = "USD Dominant"

    else:

        status = "Balanced"


    return {

        "score":

        score,

        "status":

        status,

        "reasons":

        reasons

    }


