# ==========================================================
# GOLD MARKET AI SCORE FUSION
# ==========================================================

def calculate_ai_fusion_score():

    scores = []

    reasons = []


    final_score = calculate_final_gold_score()

    confidence = calculate_confidence_v2()

    ai_rating = calculate_ai_trade_rating()

    execution = calculate_execution_score()


    scores.append(

        final_score["score"]

    )


    scores.append(

        confidence["score"]

    )


    scores.append(

        ai_rating["rating"]

    )


    scores.append(

        execution["score"]

    )


    average = sum(scores) / len(scores)


    if average >= 80:

        status = "Elite Setup"

    elif average >= 60:

        status = "Strong Setup"

    elif average >= 40:

        status = "Normal Setup"

    else:

        status = "Weak Setup"


    if final_score["score"] >= 70:

        reasons.append(

            "Final score strong"

        )


    if execution["score"] >= 70:

        reasons.append(

            "Execution condition good"

        )


    return {

        "score":

        round(

            average,

            1

        ),

        "status":

        status,

        "reasons":

        reasons

    }


