# MARKET SIGNAL CONSENSUS ENGINE
# ==========================================================

def calculate_signal_consensus():

    signals = []


    master = generate_master_signal()

    decision = trade_decision_matrix()

    ai_tree = gold_ai_decision_tree()


    signals.append(

        master["signal"]

    )


    signals.append(

        decision["decision"]

    )


    signals.append(

        ai_tree["decision"]

    )


    buy = 0

    sell = 0


    for signal in signals:

        if "BUY" in signal:

            buy += 1

        elif "SELL" in signal:

            sell += 1


    if buy > sell:

        result = "BUY CONSENSUS"

    elif sell > buy:

        result = "SELL CONSENSUS"

    else:

        result = "NO CONSENSUS"


    return {

        "result":

        result,

        "buy":

        buy,

        "sell":

        sell

    }


