# CONSENSUS DISPLAY
# ==========================================================

if st.session_state.page == "Gold":

    st.divider()

    st.subheader(

        "🤝 Signal Consensus"

    )


    consensus = calculate_signal_consensus()


    st.metric(

        "Consensus",

        consensus["result"]

    )


    col1, col2 = st.columns(

        2

    )


    with col1:

        st.metric(

            "BUY",

            consensus["buy"]

        )


    with col2:

        st.metric(

            "SELL",

            consensus["sell"]

        )


