def autonomous_decision_core():

    authority = final_authority_engine()

    risk = smart_risk_controller()

    execution = calculate_execution_score()


    core = {

        "Decision":

        "WAIT",

        "Confidence":

        0,

        "Risk":

        risk["status"],

        "Execution":

        execution["score"]

    }


    confidence = (

        authority["Score"]

        +

        execution["score"]

    ) / 2


    core["Confidence"] = round(

        confidence,

        1

    )


    if (

        authority["Decision"]

        in

        [

            "BUY",

            "SELL"

        ]

        and

        confidence >= 80

    ):

        core["Decision"] = authority["Decision"]


    elif confidence >= 50:

        core["Decision"] = "PREPARE"


    return core


