def calculate_adaptation_score():

    score = 50

    reasons = []


    health = calculate_market_health()

    optimization = optimize_strategy()

    fusion = calculate_ai_fusion_score()


    if health["health"] >= 70:

        score += 15

        reasons.append(

            "Healthy market condition"

        )


    else:

        score -= 15

        reasons.append(

            "Market instability"

        )


    if optimization["Score"] >= 70:

        score += 20

        reasons.append(

            "Strategy optimized"

        )


    if fusion["score"] >= 70:

        score += 15

        reasons.append(

            "AI system confidence high"

        )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    return {

        "score":

        score,

        "reasons":

        reasons

    }


