    adaptation = calculate_adaptation_score()


    brain["Market State"] = (

        intelligence["Trend"]

        +

        " / "

        +

        intelligence["Momentum"]

    )


    brain["Decision"] = authority["Decision"]


    brain["Confidence"] = round(

        (

            authority["Score"]

            +

            adaptation["score"]

        )

        /

        2,

        1

    )


    brain["Reason"] = (

        authority["Reasons"]

        +

        adaptation["reasons"]

    )


    return brain


