# WEOS MARKET CYCLE DETECTOR
# ==========================================================

def detect_market_cycle():

    phase = detect_market_phase()

    trend = calculate_trend_consistency()


    if (

        phase["phase"]

        ==

        "Expansion"

        and

        trend["score"]

        >=

        70

    ):

        cycle = "Trend Expansion"


    elif (

        phase["phase"]

        ==

        "Accumulation"

    ):

        cycle = "Accumulation Cycle"


    elif (

        phase["phase"]

        ==

        "Contraction"

    ):

        cycle = "Correction Cycle"


    else:

        cycle = "Transition Cycle"


    return cycle


