def calculate_entry_precision():

    precision = 50

    reasons = []


    zone = entry_zone_quality()

    confirmation = market_confirmation_v2()

    liquidity = liquidity_intelligence()


    if zone["score"] >= 70:

        precision += 20

        reasons.append(

            "Good entry zone"

        )


    if confirmation["count"] >= 3:

        precision += 20

        reasons.append(

            "Strong confirmation"

        )


    if liquidity["Status"] == "Liquidity Zone Detected":

        precision += 10

        reasons.append(

            "Liquidity supports entry"

        )


    precision = max(

        0,

        min(

            precision,

            100

        )

    )


    return {

        "score":

        precision,

        "reasons":

        reasons

    }


