# ==========================================================
# WEOS MARKET DIRECTION FUSION
# ==========================================================

def market_direction_fusion():

    buy = 0

    sell = 0

    reasons = []


    master = generate_master_signal()

    momentum = momentum_radar_v2()

    pressure = forecast_market_pressure()

    prediction = generate_market_prediction()


    signals = [

        master["signal"],

        momentum["Direction"],

        pressure["Direction"],

        prediction["Direction"]

    ]


    for signal in signals:


        if signal in [

            "BUY",

            "UP",

            "BUY PRESSURE"

        ]:

            buy += 1


        elif signal in [

            "SELL",

            "DOWN",

            "SELL PRESSURE"

        ]:

            sell += 1



    if buy > sell:

        direction = "BULLISH"

        reasons.append(

            "Majority signals support buyers"

        )


    elif sell > buy:

        direction = "BEARISH"

        reasons.append(

            "Majority signals support sellers"

        )


    else:

        direction = "NEUTRAL"

        reasons.append(

            "Signals are balanced"

        )


    strength = abs(

        buy - sell

    ) * 25


    return {

        "direction":

        direction,

        "strength":

        min(

            strength,

            100

        ),

        "buy":

        buy,

        "sell":

        sell,

        "reasons":

        reasons

    }


