# WEOS MARKET BALANCE ENGINE
# ==========================================================

def calculate_market_balance():

    balance = 50

    factors = []


    direction = market_direction_fusion()

    pressure = calculate_pressure_balance()

    dominance = calculate_gold_dominance()


    if direction["direction"] == "BULLISH":

        balance += 20

        factors.append(

            "Bullish direction"

        )


    elif direction["direction"] == "BEARISH":

        balance -= 20

        factors.append(

            "Bearish direction"

        )


    if pressure:

        if pressure["status"] == "Buyer Control":

            balance += 15

            factors.append(

                "Buyer pressure"

            )


        elif pressure["status"] == "Seller Control":

            balance -= 15

            factors.append(

                "Seller pressure"

            )


    balance += (

        dominance["score"]

        -

        50

    ) / 2


    balance = max(

        0,

        min(

            balance,

            100

        )

    )


    return {

        "balance":

        round(

            balance,

            1

        ),

        "factors":

        factors

    }


