# ==========================================================

def calculate_final_ai_score_v6():

    matrix = market_decision_matrix_v6()


    score = sum(

        matrix.values()

    ) / len(matrix)


    if score >= 80:

        status = "ELITE"

    elif score >= 65:

        status = "STRONG"

    elif score >= 50:

        status = "NORMAL"

    else:

        status = "WEAK"


    return {

        "Score":

        round(

            score,

            1

        ),

        "Status":

        status

    }


