# ==========================================================
# WEOS AI DECISION STABILITY ENGINE
# ==========================================================

def calculate_decision_stability():

    stability = 50

    reasons = []


    history = st.session_state.ai_core_memory[-20:]


    if len(history) >= 5:


        decisions = [

            item["Decision"]

            for item in history

        ]


        unique = len(

            set(decisions)

        )


        if unique <= 2:

            stability += 30

            reasons.append(

                "Decision consistency high"

            )

        else:

            stability -= 20

            reasons.append(

                "Decision changing frequently"

            )


    adaptation = ai_market_adaptation_v9()


    if adaptation["Mode"] != "DEFENSIVE":

        stability += 20


    stability = max(

        0,

        min(

            stability,

            100

        )

    )


    return {

        "Score":

        stability,

        "Reasons":

        reasons

    }


# ==========================================================
# STABILITY DISPLAY
# ==========================================================

if st.session_state.page == "Dashboard":

    st.divider()

    st.subheader(

        "📌 Decision Stability"

    )


    stability = calculate_decision_stability()


    st.progress(

        stability["Score"]

        /

        100

    )


    st.metric(

        "Stability",

        f'{stability["Score"]}/100'

    )


    for reason in stability["Reasons"]:

        st.write(

            "•",

            reason

        )


