# ==========================================================

def ai_market_sentinel():

    sentinel = {

        "Status":

        "NORMAL",

        "Threat":

        0,

        "Message":

        []

    }


    health = calculate_market_health()

    volatility = calculate_volatility()

    reversal = detect_smart_money_reversal()


    threat = 0


    if health["health"] < 50:

        threat += 30

        sentinel["Message"].append(

            "Market health declining"

        )


    if volatility:

        if volatility["latest"] > (

            volatility["average"]

            *

            2

        ):

            threat += 30

            sentinel["Message"].append(

                "Extreme volatility"

            )


    if reversal["risk"] >= 60:

        threat += 40

        sentinel["Message"].append(

            "Reversal danger"

        )


    sentinel["Threat"] = min(

        threat,

        100

    )


    if threat >= 70:

        sentinel["Status"] = "DANGER"


    elif threat >= 40:

        sentinel["Status"] = "WARNING"


    return sentinel


# ==========================================================
# SENTINEL DISPLAY
# ==========================================================

