# WEOS AI MARKET BIAS ENGINE V12
# ==========================================================

def ai_market_bias_v12():

    bias = {

        "Bias":

        "NEUTRAL",

        "Score":

        50,

        "Reasons":

        []

    }


    direction = market_direction_fusion()

    momentum = momentum_radar_v2()

    dominance = calculate_gold_dominance()


    score = 50


    if direction["direction"] == "BULLISH":

        score += 20

        bias["Reasons"].append(

            "Bullish consensus"

        )


    elif direction["direction"] == "BEARISH":

        score -= 20

        bias["Reasons"].append(

            "Bearish consensus"

        )


    if momentum["Direction"] == "UP":

        score += 15

        bias["Reasons"].append(

            "Momentum upward"

        )


    elif momentum["Direction"] == "DOWN":

        score -= 15

        bias["Reasons"].append(

            "Momentum downward"

        )


    score += (

        dominance["score"]

        -

        50

    ) / 2


    score = max(

        0,

        min(

            score,

            100

        )

    )


    bias["Score"] = score


    if score >= 65:

        bias["Bias"] = "BULLISH"


    elif score <= 35:

        bias["Bias"] = "BEARISH"


    return bias


