# ==========================================================

def ai_market_rating_v16():

    scores = ai_market_scoring_v16()


    average = sum(

        scores.values()

    ) / len(scores)


    if average >= 85:

        rating = "A+ PREMIUM"


    elif average >= 70:

        rating = "A QUALITY"


    elif average >= 55:

        rating = "B NORMAL"


    elif average >= 40:

        rating = "C WEAK"


    else:

        rating = "D AVOID"


    return {

        "Rating":

        rating,

        "Score":

        round(

            average,

            1

        )

    }


