def gold_final_signal_v10():

    matrix = gold_decision_matrix_v10()

    score = sum(

        matrix.values()

    ) / len(matrix)


    if score >= 75:

        signal = "STRONG BUY"


    elif score <= 35:

        signal = "STRONG SELL"


    elif score >= 60:

        signal = "BUY WATCH"


    elif score <= 45:

        signal = "SELL WATCH"


    else:

        signal = "NO SIGNAL"


    return {

        "Signal":

        signal,

        "Score":

        round(

            score,

            1

        )

    }


