def gold_entry_zone_engine_v11():

    zone = {

        "Zone":

        "UNKNOWN",

        "Type":

        "NONE",

        "Confidence":

        50,

        "Reason":

        []

    }


    price = current_gold_price()

    support = detect_support_zone()

    resistance = detect_resistance_zone()

    structure = analyze_price_action()


    if price <= support["Level"]:

        zone["Zone"] = "SUPPORT ENTRY"

        zone["Type"] = "BUY AREA"

        zone["Confidence"] = 75

        zone["Reason"].append(

            "Near support zone"

        )


    elif price >= resistance["Level"]:

        zone["Zone"] = "RESISTANCE ENTRY"

        zone["Type"] = "SELL AREA"

        zone["Confidence"] = 75

        zone["Reason"].append(

            "Near resistance zone"

        )


    else:

        zone["Zone"] = "MID RANGE"

        zone["Type"] = "WAIT"

        zone["Confidence"] = 40


    if structure["Structure"] != "Unknown":

        zone["Confidence"] += 10

        zone["Reason"].append(

            "Structure confirmed"

        )


    zone["Confidence"] = min(

        zone["Confidence"],

        100

    )


    return zone


