def precision_entry_engine_v18():

    entry = {

        "Action":

        "WAIT",

        "Direction":

        "NONE",

        "Confidence":

        0,

        "Reason":

        []

    }


    confluence = smart_money_confluence_v17()

    signal = gold_final_signal_v10()

    zone = gold_entry_zone_engine_v11()


    score = (

        confluence["Score"]

        +

        signal["Score"]

        +

        zone["Confidence"]

    ) / 3


    if confluence["Signal"] != "WAIT":

        entry["Direction"] = confluence["Signal"]

        entry["Reason"].append(

            "Smart money confirmation"

        )


    if zone["Type"] != "NONE":

        entry["Reason"].append(

            "Entry zone detected"

        )


    entry["Confidence"] = round(

        score,

        1

    )


    if score >= 80:

        entry["Action"] = "EXECUTE"


    elif score >= 60:

        entry["Action"] = "PREPARE"


    else:

        entry["Action"] = "WAIT"


    return entry


