    quality = ai_trade_quality_supervisor_v18()

    protection = ai_position_protection_v24()

    lifecycle = ai_trade_lifecycle_v23()


    score = (

        quality["Score"]

        +

        (

            100

            -

            protection["Level"]

        )

        +

        lifecycle["Confidence"]

    ) / 3


    review["Score"] = round(

        score,

        1

    )


    if score >= 80:

        review["Rating"] = "EXCELLENT"

        review["Feedback"].append(

            "Optimal setup"

        )


    elif score >= 60:

        review["Rating"] = "GOOD"

        review["Feedback"].append(

            "Acceptable setup"

        )


    else:

        review["Rating"] = "WEAK"

        review["Feedback"].append(

            "Need improvement"

        )


    return review


