# ==========================================================
# WEOS AI MULTI TIMEFRAME FUSION V34
# ==========================================================

def ai_multi_timeframe_fusion_v34():

    mtf = {

        "Direction":

        "WAIT",

        "Score":

        50,

        "Frames":

        {}

    }


    d1 = analyze_timeframe("D1")

    h4 = analyze_timeframe("H4")

    h1 = analyze_timeframe("H1")

    m15 = analyze_timeframe("M15")


    mtf["Frames"]["D1"] = d1

    mtf["Frames"]["H4"] = h4

    mtf["Frames"]["H1"] = h1

    mtf["Frames"]["M15"] = m15


    bullish = 0

    bearish = 0


    for frame in mtf["Frames"].values():

        if frame == "BULLISH":

            bullish += 1


        elif frame == "BEARISH":

            bearish += 1


    score = 50 + (

        bullish * 12

    ) - (

        bearish * 12

    )


    score = max(

        0,

        min(

            score,

            100

        )

    )


    mtf["Score"] = score


    if score >= 70:

        mtf["Direction"] = "BUY"


    elif score <= 35:

        mtf["Direction"] = "SELL"


    return mtf


