    if rr["Risk Reward"] >= 3:

        rr["Quality"] = "EXCELLENT"

        rr["Decision"] = "ACCEPT"


    elif rr["Risk Reward"] >= 2:

        rr["Quality"] = "GOOD"

        rr["Decision"] = "ACCEPT"


    else:

        rr["Quality"] = "WEAK"

        rr["Decision"] = "REJECT"


    return rr


