# WEOS AI GOLD FINAL SCORING ENGINE V69
# ==========================================================

def ai_gold_final_score_v69():

    score = {

        "Total":

        0,

        "Grade":

        "C",

        "Components":

        {}

    }


    components = {

        "Macro":

        gold_macro_ai_fusion_v7()["Score"],

        "Structure":

        market_structure_ai_v16()["Score"],

        "Momentum":

        ai_gold_momentum_fusion_v56()["Strength"],

        "Quality":

        ai_trade_quality_score_v36()["Score"],

        "Risk":

        100 - ai_position_protection_v24()["Level"]

    }


    score["Components"] = components


    total = sum(

        components.values()

    ) / len(

        components

    )


    score["Total"] = round(

        total,

        1

    )


    if total >= 85:

        score["Grade"] = "A+"


    elif total >= 70:

        score["Grade"] = "A"


    elif total >= 55:

        score["Grade"] = "B"


    else:

        score["Grade"] = "C"


    return score


