# ==========================================================

def ai_gold_news_impact_v74():

    news = {

        "Impact":

        "LOW",

        "Direction":

        "NEUTRAL",

        "Score":

        50,

        "Reason":

        []

    }


    macro = gold_macro_ai_fusion_v7()

    session = ai_gold_session_analyzer_v73()

    volatility = volatility_engine_v5()


    score = 50


    if macro["Score"] >= 75:

        score += 15

        news["Direction"] = "BULLISH"

        news["Reason"].append(

            "Strong macro support"

        )


    elif macro["Score"] <= 35:

        score -= 15

        news["Direction"] = "BEARISH"

        news["Reason"].append(

            "Macro pressure"

        )


    if session["Activity"] == "HIGH":

        score += 10

        news["Reason"].append(

            "Active market session"

        )


    if volatility["Level"] == "HIGH":

        score += 10

        news["Reason"].append(

            "News volatility possible"

        )


    news["Score"] = max(

        0,

        min(

            score,

            100

        )

    )


    if score >= 70:

        news["Impact"] = "HIGH"


    elif score >= 50:

        news["Impact"] = "MEDIUM"


    return news


