def ai_entry_confirmation_matrix_v81():

    matrix = {

        "Score":

        0,

        "Status":

        "REJECT",

        "Signals":

        {}

    }


    signals = {

        "Trend":

        market_structure_ai_v16()["Bias"],

        "Momentum":

        ai_gold_momentum_fusion_v56()["Direction"],

        "Order Flow":

        ai_gold_order_flow_v80()["Direction"],

        "Liquidity":

        ai_gold_liquidity_map_v76()["Pressure"],

        "Smart Money":

        ai_gold_smart_money_convergence_v77()["Direction"]

    }


    matrix["Signals"] = signals


    score = 50


    buy_count = 0

    sell_count = 0


    for value in signals.values():

        if value in [

            "BUY",

            "BULLISH"

        ]:

            buy_count += 1


        elif value in [

            "SELL",

            "BEARISH"

        ]:

            sell_count += 1


    score += (

        buy_count * 10

    )

    score -= (

        sell_count * 10

    )


    matrix["Score"] = max(

        0,

        min(

            score,

            100

        )

    )


    if matrix["Score"] >= 80:

        matrix["Status"] = "APPROVED"


    elif matrix["Score"] >= 60:

        matrix["Status"] = "WATCH"


    return matrix


