    if momentum["Direction"] == "BUY":

        fusion["Direction"] = "BUY"


    elif momentum["Direction"] == "SELL":

        fusion["Direction"] = "SELL"


    if confidence >= 85:

        fusion["Signal"] = "STRONG SIGNAL"


    elif confidence >= 65:

        fusion["Signal"] = "POSSIBLE SIGNAL"


    return fusion


